const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

---

#### 5. No Request Body Parsing Limits
If you ever add `POST`/`PUT` routes, missing body-size limits enable payload-flooding attacks.

```js
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));
```

---

#### 6. No CORS Configuration
Without explicit CORS rules, behavior depends entirely on the hosting environment — easy to misconfigure.

```js
const cors = require('cors');

app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || [],
  methods: ['GET'],
}));
```

---

### 🟡 Best Practice Improvements

#### 7. `/health` Timestamp Info Disclosure
The `timestamp` field in the health response leaks server-side timing info, which can aid timing-based attacks.

```js
// Consider omitting the timestamp, or gating it behind auth
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});
```

---

#### 8. Add Query Parameter Validation (for future-proofing)
If query params are added (e.g., `/users?id=1`), always validate and sanitize them. Consider [zod](https://github.com/colinhacks/zod) or [joi](https://joi.dev/):

```js
const { z } = require('zod');

const userQuerySchema = z.object({
  id: z.coerce.number().int().positive().optional(),
});

app.get('/users', (req, res, next) => {
  const result = userQuerySchema.safeParse(req.query);
  if (!result.success) {
    return res.status(400).json({ error: 'Invalid query parameters', details: result.error.flatten() });
  }
  // ...
});
```

